1	export function shouldShowLoginFallbackError(err: any): boolean {
2	  if (!err) return true;
3	
4	  // Angular HttpErrorResponse instances have a numeric status. The global HTTP
5	  // interceptor already shows the specific backend/network message for those.
6	  if (typeof err.status === 'number') return false;
7	
8	  const code = err.errorCode || err.message;
9	  return code !== 'user_cancelled';
10	}
