1	import { Injectable, NgZone, OnDestroy } from '@angular/core';
2	import { MatSnackBar } from '@angular/material/snack-bar';
3	import { AuthService } from './auth.service';
4	import { ConfigService } from 'src/app/helpers/services/config.service';
5	import { MatDialog } from '@angular/material/dialog'; 
6	
7	@Injectable({ providedIn: 'root' })
8	export class IdleTimeoutService implements OnDestroy {
9	  private timeoutId: any;
10	  private warningTimeoutId: any;
11	  private warningSnackbarRef: any;
12	  private idleTime:number;
13	  private readonly warningTime = 5 * 60 * 1000; // 5 minutes warning
14	  private eventListeners: { [key: string]: EventListener } = {};
15	
16	  constructor(
17	    private zone: NgZone,
18	    private authService: AuthService,
19	    private configService: ConfigService,
20	    private snackBar: MatSnackBar,  
21	    private dialog: MatDialog
22	
23	  ) { }
24	
25	  async startWatching(): Promise<void> {
26	    await this.setIdleTimeForUser();
27	    this.resetTimers();
28	    this.setupEventListeners();
29	   
30	  }
31	
32	  private async setIdleTimeForUser(): Promise<void> {
33	    const user = await this.authService.getUserFromToken() as any
34	    const excludedUserIds = this.configService.get('excludedUserIds') as number[];
35	
36	    const isAdmin = excludedUserIds?.includes(user.user_id);
37	
38	    this.idleTime = isAdmin
39	      ? 12 * 60 * 60 * 1000 // 12 hours for admins
40	      : 2 * 60 * 60 * 1000; // 2 hours for others
41	  }
42	
43	  private setupEventListeners(): void {
44	    // Clear existing listeners first
45	    this.removeEventListeners();
46	
47	    const events = [
48	      'pointermove',
49	      'pointerdown',
50	      'mousemove',
51	      'mousedown',
52	      'click',
53	      'wheel',
54	      'scroll',
55	      'keydown',
56	      'contextmenu'
57	    ]
58	
59	    events.forEach(evt => {
60	      const listener = () => {
61	        this.zone.runOutsideAngular(() => {
62	          this.resetTimers();
63	        });
64	      };
65	      this.eventListeners[evt] = listener;
66	      window.addEventListener(evt, listener, { passive: true, capture: true });
67	    });
68	  }
69	
70	  private removeEventListeners(): void {
71	    Object.entries(this.eventListeners).forEach(([event, listener]) => {
72	      window.removeEventListener(event, listener, { capture: true });
73	    });
74	    this.eventListeners = {};
75	  }
76	
77	  private resetTimers(): void {
78	    this.clearTimers();
79	    this.dismissWarning();
80	
81	    // Set warning timer
82	    this.warningTimeoutId = setTimeout(() => {
83	      this.zone.run(() => this.showTimeoutWarning());
84	    }, this.idleTime - this.warningTime);
85	
86	    // Set logout timer
87	    this.timeoutId = setTimeout(() => {
88	      this.zone.run(() => {
89	        this.dismissWarning(); // Clear warning before logout
90	        this.dialog.closeAll(); // ✅ Close all open Angular Material dialogs
91	        this.authService.logout('/login', 'You were automatically logged out due to inactivity');
92	      });
93	    }, this.idleTime);
94	  }
95	
96	  private showTimeoutWarning(): void {
97	    // Clear any existing warning
98	    this.dismissWarning();
99	
100	    const minutesLeft = Math.ceil(this.warningTime / 60000);
101	    this.warningSnackbarRef = this.snackBar.open(
102	      `You'll be logged out in ${minutesLeft} minutes due to inactivity`,
103	      'STAY LOGGED IN',
104	      {
105	        duration: this.warningTime,
106	        panelClass: ['warning-snackbar'],
107	        horizontalPosition: 'center',
108	        verticalPosition: 'top'
109	      }
110	    );
111	
112	    this.warningSnackbarRef.onAction().subscribe(() => {
113	      this.resetTimers();
114	    });
115	  }
116	
117	  private dismissWarning(): void {
118	    if (this.warningSnackbarRef) {
119	      this.warningSnackbarRef.dismiss();
120	      this.warningSnackbarRef = null;
121	    }
122	  }
123	
124	  private clearTimers(): void {
125	    clearTimeout(this.timeoutId);
126	    clearTimeout(this.warningTimeoutId);
127	  }
128	
129	  stopWatching(): void {
130	    this.clearTimers();
131	    this.dismissWarning();
132	    this.removeEventListeners();
133	  }
134	
135	  ngOnDestroy(): void {
136	    this.stopWatching();
137	  }
138	}

